// src/module/medicine/medicine.service.ts
var getMedicineById = async (id) => {
  const result = await prisma.medicine.findUniqueOrThrow({
    where: {
      id
    },
    include: {
      reviews: true
    }
  });
  return result;
};
var getAllMedicine = async ({ search, price, category, page, limit, sortBy, sortOrder }) => {
  const skip = (page - 1) * limit;
  const priceNum = Number(price);
  const andConditions = [];
  if (search) {
    andConditions.push({
      name: {
        contains: search,
        mode: "insensitive"
      }
    });
  }
  if (priceNum) {
    andConditions.push({
      price: priceNum
    });
  }
  if (category) {
    andConditions.push({
      categoryName: category
    });
  }
  const result = await prisma.medicine.findMany({
    take: limit,
    skip,
    where: {
      AND: andConditions
    },
    orderBy: sortBy && sortOrder ? {
      [sortBy]: sortOrder
    } : { price: "asc" },
    include: {
      orders: true,
      reviews: true
    }
  });
  const total = await prisma.medicine.count({
    // take : limit,
    // skip,
    where: {
      AND: andConditions
    }
  });
  return {
    data: result,
    pagination: {
      total,
      page,
      limit,
      totalPages: Math.ceil(total / limit)
    }
  };
};
var medicineService = {
  getMedicineById,
  getAllMedicine
};

