var createCategory = async (data) => {
  const result = await prisma.category.create({
    data
  });
  return result;
};
var getSingleCategory = async (categoryName) => {
  const result = await prisma.category.findUnique({
    where: {
      categoryName
    },
    include: {
      medicines: {
        select: {
          name: true,
          price: true
        }
      }
    }
  });
  return result;
};
